// Delta-Erkennung: Nur neue/geaenderte Dateien verarbeiten
// Letzer Sync-Zeitpunkt aus Static Data
const staticData = $getWorkflowStaticData('global');
const lastSync = staticData.lastSync || '1970-01-01T00:00:00Z';
const lastSyncDate = new Date(lastSync);

const supportedTypes = ['.pdf', '.docx', '.doc', '.txt', '.md', '.xlsx', '.pptx', '.odt', '.ods'];

const items = $input.all();
const results = [];

for (const item of items) {
  const fileName = item.json.basename || item.json.name || '';
  const ext = fileName.substring(fileName.lastIndexOf('.')).toLowerCase();
  const lastModified = new Date(item.json.lastmod || item.json.getlastmodified || '1970-01-01');

  if (!supportedTypes.includes(ext)) continue;

  if (lastModified > lastSyncDate) {
    results.push({
      json: {
        ...item.json,
        fileName: fileName,
        filePath: item.json.filename || item.json.path || '',
        fileExtension: ext,
        lastModified: lastModified.toISOString(),
        source: 'nextcloud',
        source_id: item.json.fileid ? String(item.json.fileid) : item.json.filename,
        action: 'add_or_update'
      }
    });
  }
}

// Sync-Zeitpunkt aktualisieren
staticData.lastSync = new Date().toISOString();

return results.length > 0 ? results : [{ json: { action: 'none' } }];

// Text aus Datei extrahieren (PDF, DOCX, TXT, MD)
const item = $input.first();
const ext = item.json.fileExtension;
const fileName = item.json.fileName;
let text = '';
let needs_ocr = false;

if (ext === '.txt' || ext === '.md') {
  // Klartext direkt lesen
  const binaryData = item.binary?.data;
  if (binaryData) {
    text = Buffer.from(binaryData.data, 'base64').toString('utf-8');
  }
} else if (ext === '.pdf') {
  // PDF: Wird spaeter via Embedding oder OCR verarbeitet
  // Hier erstmal Binary durchreichen
  const binaryData = item.binary?.data;
  if (binaryData) {
    // Versuch Text zu extrahieren (fuer text-basierte PDFs)
    text = '[PDF_BINARY]';  // Marker fuer downstream OCR/Embedding
    needs_ocr = true;
  }
} else if (ext === '.docx' || ext === '.odt') {
  // DOCX/ODT: n8n Extract Node nutzen
  text = '[NEEDS_EXTRACTION]';
} else {
  text = '[UNSUPPORTED_FORMAT]';
}

// OCR-Erkennung: Weniger als 50 Zeichen = vermutlich Scan
if (text.length > 0 && text.length < 50 && !text.startsWith('[')) {
  needs_ocr = true;
  text = '[OCR_NEEDED] ' + text;
}

return [{
  json: {
    ...item.json,
    text: text,
    needs_ocr: needs_ocr,
    charCount: text.length
  },
  binary: item.binary
}];

// Chunking: Text in Abschnitte zerlegen
const item = $input.first();
const text = item.json.text;
const CHUNK_SIZE = parseInt($env.CHUNK_SIZE || '500');
const CHUNK_OVERLAP = parseInt($env.CHUNK_OVERLAP || '75');

// Wenn Text zu kurz oder Marker: als einzelnen Chunk zurueckgeben
if (!text || text.startsWith('[') || text.length < 50) {
  return [{ json: { ...item.json, chunks: [text], chunkCount: 1 } }];
}

const chunks = [];
let start = 0;

while (start < text.length) {
  let end = Math.min(start + CHUNK_SIZE, text.length);

  // Am Satzende schneiden wenn moeglich
  if (end < text.length) {
    const lastPeriod = text.lastIndexOf('. ', end);
    const lastNewline = text.lastIndexOf('\n', end);
    const bestBreak = Math.max(lastPeriod, lastNewline);
    if (bestBreak > start + CHUNK_SIZE * 0.5) {
      end = bestBreak + 1;
    }
  }

  const chunk = text.substring(start, end).trim();
  if (chunk.length > 0) {
    chunks.push(chunk);
  }

  start = end - CHUNK_OVERLAP;
  if (start >= text.length) break;
}

return [{ json: { ...item.json, chunks: chunks, chunkCount: chunks.length } }];

// Alte Chunks loeschen + Neue einfuegen
const item = $input.first();
const chunks = item.json.chunks;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const tenantId = $env.TENANT_ID || 'clx-digital';
const embeddingProvider = $env.EMBEDDING_PROVIDER || 'ollama';
const ollamaUrl = $env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434';
const embeddingModel = $env.EMBEDDING_MODEL || 'nomic-embed-text';

// 1. Alte Chunks loeschen
await fetch(`${supabaseUrl}/rest/v1/rpc/delete_by_source_id`, {
  method: 'POST',
  headers: {
    'apikey': supabaseKey,
    'Authorization': `Bearer ${supabaseKey}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    p_source: 'nextcloud',
    p_source_id: item.json.source_id
  })
});

// 2. Pro Chunk: Embedding generieren + in Supabase speichern
const results = [];
for (let i = 0; i < chunks.length; i++) {
  const chunk = chunks[i];

  // Embedding generieren (Ollama)
  let embedding = null;
  if (embeddingProvider === 'ollama') {
    const embResp = await fetch(`${ollamaUrl}/api/embeddings`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: embeddingModel, prompt: chunk })
    });
    const embData = await embResp.json();
    embedding = embData.embedding;
  }

  // In Supabase speichern
  if (embedding) {
    const insertResp = await fetch(`${supabaseUrl}/rest/v1/documents`, {
      method: 'POST',
      headers: {
        'apikey': supabaseKey,
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        source: 'nextcloud',
        source_id: item.json.source_id,
        file_name: item.json.fileName,
        file_path: item.json.filePath,
        content: chunk,
        chunk_index: i,
        embedding: `[${embedding.join(',')}]`,
        tenant_id: tenantId,
        metadata: { charCount: chunk.length }
      })
    });
    results.push({ chunk: i, status: insertResp.status });
  }

  // Kurze Pause (Ollama schonen)
  if (i < chunks.length - 1) {
    await new Promise(r => setTimeout(r, 500));
  }
}

return [{ json: { fileName: item.json.fileName, chunksInserted: results.length, results } }];
